payload.text:
To implement the "Plan Whole Month" feature with weekday selection, I will update `components/ResourcePlanner.tsx`.

The changes include:
1.  **State Management**: Adding `isRepeatMode` and `repeatDays` states to control the bulk assignment logic.
2.  **Modal UI**: Inserting a "Repeat for entire month" section within the assignment modal. This will include a weekday selector (Mon-Sun) to let users specify exactly which days to target (e.g., "Monday, Friday").
3.  **Save Logic**: Updating `handleSaveAssignments` to handle the bulk operation. When "Repeat" is active, it will iterate through all matching days in the month, clear their existing assignments, and apply the current selection, effectively "copying" the configuration to the whole month for the selected weekdays.

# Updated files:

## components/ResourcePlanner.tsx

```tsx
import React, { useState, useMemo, useEffect } from 'react';
import { 
  format, 
  eachDayOfInterval, 
  startOfMonth, 
  endOfMonth, 
  addMonths, 
  isWeekend, 
  isSameDay, 
  isToday,
  getISOWeek,
  startOfQuarter,
  addQuarters,
  isSameQuarter,
  isSameMonth,
  getDay
} from 'date-fns';
import { ChevronLeft, ChevronRight, Plus, X, Info, Calendar, FileSpreadsheet, Share2, Check, GripVertical, Repeat } from 'lucide-react';
import { Employee, Project, Assignment, TimeScale } from '../types';
import { PASTEL_VARIANTS, MOCK_PROJECTS } from '../constants';
import { Button } from './ui/Button';

interface ResourcePlannerProps {
  employees: Employee[];
  assignments: Assignment[];
  onAssignmentChange: (assignments: Assignment[]) => void;
  initialDate?: Date;
}

export const ResourcePlanner: React.FC<ResourcePlannerProps> = ({ 
  employees, 
  assignments, 
  onAssignmentChange,
  initialDate
}) => {
  const [currentDate, setCurrentDate] = useState(initialDate || new Date());
  const [timeScale, setTimeScale] = useState<TimeScale>(TimeScale.MONTH);
  const [selectedCell, setSelectedCell] = useState<{empId: string, date: Date} | null>(null);
  const [showLegend, setShowLegend] = useState(false);

  // Multi-select state for the modal
  const [selectedProjectIds, setSelectedProjectIds] = useState<string[]>([]);

  // Bulk Assign / Repeat Mode state
  const [isRepeatMode, setIsRepeatMode] = useState(false);
  const [repeatDays, setRepeatDays] = useState<number[]>([]); // 0=Sun, 1=Mon...

  // Drag and Drop state
  const [draggingEmpId, setDraggingEmpId] = useState<string | null>(null);
  const [draggingAssignmentId, setDraggingAssignmentId] = useState<string | null>(null);

  // Initialize date if initialDate prop changes (e.g. version switch)
  useEffect(() => {
    if (initialDate) {
        setCurrentDate(initialDate);
    }
  }, [initialDate]);

  // When selected cell changes, initialize the buffer with existing assignments
  useEffect(() => {
    if (selectedCell) {
        const dateStr = format(selectedCell.date, 'yyyy-MM-dd');
        const existingIds = assignments
            .filter(a => a.employeeId === selectedCell.empId && a.date === dateStr)
            .map(a => a.projectId);
        setSelectedProjectIds(existingIds);

        // Reset repeat mode on new selection
        setIsRepeatMode(false);
        // Default repeat day to the selected day's day-of-week
        setRepeatDays([getDay(selectedCell.date)]);
    }
  }, [selectedCell, assignments]);

  // Derive months based on timescale
  const quarterMonths = useMemo(() => {
    if (timeScale === TimeScale.MONTH) {
        const start = startOfMonth(currentDate);
        const end = endOfMonth(currentDate);
        return [{
            name: format(start, 'MMMM'),
            fullName: format(start, 'MMMM yyyy'),
            date: start,
            days: eachDayOfInterval({ start, end })
        }];
    } else {
        const start = startOfQuarter(currentDate);
        return [0, 1, 2].map(i => {
            const mStart = addMonths(start, i);
            return {
                name: format(mStart, 'MMMM'),
                fullName: format(mStart, 'MMMM yyyy'),
                date: mStart,
                days: eachDayOfInterval({ start: startOfMonth(mStart), end: endOfMonth(mStart) })
            };
        });
    }
  }, [currentDate, timeScale]);

  const headerTitle = useMemo(() => {
    if (timeScale === TimeScale.MONTH) {
      return format(currentDate, 'MMMM yyyy');
    }
    const quarter = Math.floor(startOfQuarter(currentDate).getMonth() / 3) + 1;
    return `Q${quarter} ${format(currentDate, 'yyyy')}`;
  }, [currentDate, timeScale]);

  const isCurrentPeriod = useMemo(() => {
    const today = new Date();
    if (timeScale === TimeScale.MONTH) {
      return isSameMonth(currentDate, today);
    }
    return isSameQuarter(quarterMonths[0].date, today);
  }, [currentDate, timeScale, quarterMonths]);

  const handlePrev = () => {
    if (timeScale === TimeScale.QUARTER) {
      setCurrentDate(prev => addQuarters(prev, -1));
    } else {
      setCurrentDate(prev => addMonths(prev, -1));
    }
  };

  const handleNext = () => {
    if (timeScale === TimeScale.QUARTER) {
      setCurrentDate(prev => addQuarters(prev, 1));
    } else {
      setCurrentDate(prev => addMonths(prev, 1));
    }
  };

  // --- Drag and Drop Logic ---

  const handleDragStart = (e: React.DragEvent, assignment: Assignment) => {
    e.dataTransfer.setData('assignmentId', assignment.id);
    e.dataTransfer.setData('empId', assignment.employeeId);
    e.dataTransfer.effectAllowed = "move";
    setDraggingEmpId(assignment.employeeId); // Set global state for UI feedback
    setDraggingAssignmentId(assignment.id);
  };

  const handleDragEnd = () => {
    setDraggingEmpId(null);
    setDraggingAssignmentId(null);
  };

  const handleDragOver = (e: React.DragEvent, targetEmpId: string) => {
    e.preventDefault(); // Necessary to allow drop
    // Only allow drop if it's the same employee
    if (draggingEmpId === targetEmpId) {
        e.dataTransfer.dropEffect = "move";
    } else {
        e.dataTransfer.dropEffect = "none";
    }
  };

  const handleDrop = (e: React.DragEvent, targetEmpId: string, targetDate: Date) => {
    e.preventDefault();
    setDraggingEmpId(null);
    setDraggingAssignmentId(null);

    const assignmentId = e.dataTransfer.getData('assignmentId');
    const srcEmpId = e.dataTransfer.getData('empId');

    // Row constraint check
    if (srcEmpId !== targetEmpId) return;

    const targetDateStr = format(targetDate, 'yyyy-MM-dd');

    // Max projects constraint check (optional, but good for data integrity)
    // We filter assignments on target date, excluding the one being dragged (if it was already there)
    const targetAssignments = assignments.filter(a => a.employeeId === targetEmpId && a.date === targetDateStr && a.id !== assignmentId);

    // If the dropped assignment is already on this day (dragging onto itself), do nothing
    const currentAssignment = assignments.find(a => a.id === assignmentId);
    if (currentAssignment && currentAssignment.date === targetDateStr) return;

    const newAssignments = assignments.map(a => {
        if (a.id === assignmentId) {
            return { ...a, date: targetDateStr };
        }
        return a;
    });

    onAssignmentChange(newAssignments);
  };

  // --- Modal Logic ---

  const handleCellClick = (empId: string, date: Date) => {
    setSelectedCell({ empId, date });
  };

  const toggleProjectInModal = (projectId: string) => {
      setSelectedProjectIds(prev => {
          if (prev.includes(projectId)) {
              return prev.filter(id => id !== projectId);
          } else {
              return [...prev, projectId];
          }
      });
  };

  const toggleRepeatDay = (dayIndex: number) => {
    setRepeatDays(prev => 
        prev.includes(dayIndex) 
            ? prev.filter(d => d !== dayIndex) 
            : [...prev, dayIndex]
    );
  };

  const handleSaveAssignments = () => {
      if (!selectedCell) return;

      let newAssignments = [...assignments];

      if (isRepeatMode) {
          // Bulk Mode
          const monthStart = startOfMonth(selectedCell.date);
          const monthEnd = endOfMonth(selectedCell.date);
          const allDaysInMonth = eachDayOfInterval({ start: monthStart, end: monthEnd });

          // Filter days that match selected weekdays
          const targetDays = allDaysInMonth.filter(d => repeatDays.includes(getDay(d)) && !isWeekend(d));
          const targetDateStrings = targetDays.map(d => format(d, 'yyyy-MM-dd'));

          // 1. Remove ALL existing assignments for this employee on the target days (Overwrite strategy)
          newAssignments = newAssignments.filter(a => {
              if (a.employeeId === selectedCell.empId && targetDateStrings.includes(a.date)) {
                  return false;
              }
              return true;
          });

          // 2. Add the selected projects to ALL target days
          const assignmentsToAdd: Assignment[] = [];
          targetDays.forEach(day => {
              const dateStr = format(day, 'yyyy-MM-dd');
              selectedProjectIds.forEach(pid => {
                  assignmentsToAdd.push({
                      id: Math.random().toString(36).substr(2, 9),
                      employeeId: selectedCell.empId,
                      projectId: pid,
                      date: dateStr
                  });
              });
          });

          newAssignments = [...newAssignments, ...assignmentsToAdd];
      } else {
          // Single Day Mode
          const dateStr = format(selectedCell.date, 'yyyy-MM-dd');

          // 1. Remove assignments for this cell that are NOT in selectedProjectIds
          newAssignments = newAssignments.filter(a => {
              if (a.employeeId === selectedCell.empId && a.date === dateStr) {
                  return selectedProjectIds.includes(a.projectId);
              }
              return true;
          });

          // 2. Add new assignments for IDs that are in selectedProjectIds but not yet assigned
          const currentAssignedIds = assignments
            .filter(a => a.employeeId === selectedCell.empId && a.date === dateStr)
            .map(a => a.projectId);

          const newAssignmentsToAdd = selectedProjectIds
            .filter(pid => !currentAssignedIds.includes(pid))
            .map(pid => ({
                id: Math.random().toString(36).substr(2, 9),
                employeeId: selectedCell.empId,
                projectId: pid,
                date: dateStr
            }));

          newAssignments = [...newAssignments, ...newAssignmentsToAdd];
      }

      onAssignmentChange(newAssignments);
      setSelectedCell(null);
  };

  const removeAssignment = (assignmentId: string, e: React.MouseEvent) => {
    e.stopPropagation();
    onAssignmentChange(assignments.filter(a => a.id !== assignmentId));
  };

  const getAssignmentsForCell = (empId: string, date: Date) => {
    const dStr = format(date, 'yyyy-MM-dd');
    return assignments
      .filter(a => a.employeeId === empId && a.date === dStr)
      .map(a => ({
        assignment: a,
        project: MOCK_PROJECTS.find(p => p.id === a.projectId)
      }));
  };

  // Helper to calculate utilization
  const getUtilization = (empId: string, monthDays: Date[]) => {
    const workingDays = monthDays.filter(d => !isWeekend(d)).length;
    // Count days with at least one assignment
    const assignedDays = new Set(assignments
      .filter(a => a.employeeId === empId && monthDays.some(d => isSameDay(d, new Date(a.date))))
      .map(a => a.date)
    ).size;

    const percentage = workingDays > 0 ? Math.round((assignedDays / workingDays) * 100) : 0;
    return { percentage, assignedDays, workingDays };
  };

  const updateSelectedDate = (dateStr: string) => {
    if (!selectedCell) return;
    if (!dateStr) return;
    const [y, m, d] = dateStr.split('-').map(Number);
    setSelectedCell({ ...selectedCell, date: new Date(y, m - 1, d) });
  };

  const handleExportInternal = () => {
    alert("Generating Excel export for Internal Stakeholders analysis...");
  };

  const handleExportClient = () => {
    alert("Generating Excel export for Client distribution...");
  };

  return (
    <div className="flex flex-col h-full bg-white relative">
      {/* Toolbar */}
      <div className="flex items-center justify-between px-6 py-4 border-b border-charcoal-100 bg-white/80 backdrop-blur-sm sticky top-0 z-30">
        <div className="flex items-center gap-6">
          <div className="flex items-center bg-charcoal-100 rounded-lg p-1">
            <Button 
              variant={timeScale === TimeScale.MONTH ? 'primary' : 'ghost'} 
              size="sm" 
              onClick={() => setTimeScale(TimeScale.MONTH)}
              className="shadow-none"
            >
              Month
            </Button>
            <Button 
              variant={timeScale === TimeScale.QUARTER ? 'primary' : 'ghost'} 
              size="sm" 
              onClick={() => setTimeScale(TimeScale.QUARTER)}
              className="shadow-none"
            >
              Quarter
            </Button>
          </div>
          <div className="flex items-center gap-2">
            <Button variant="outline" size="icon" onClick={handlePrev}>
              <ChevronLeft className="w-4 h-4" />
            </Button>
            <span className="font-semibold text-lg min-w-[160px] text-center flex flex-col items-center leading-tight">
              <span>{headerTitle}</span>
              {isCurrentPeriod && (
                <span className="text-[10px] text-blue-600 font-bold bg-blue-50 px-1.5 rounded uppercase tracking-wider mt-0.5">
                  Current
                </span>
              )}
            </span>
            <Button variant="outline" size="icon" onClick={handleNext}>
              <ChevronRight className="w-4 h-4" />
            </Button>
          </div>
        </div>

        <div className="flex items-center gap-4">
            {/* Export Actions */}
            <div className="flex items-center gap-2 border-r border-charcoal-200 pr-4 mr-1">
                <Button variant="ghost" size="sm" onClick={handleExportInternal} className="gap-2 text-charcoal-600" title="Export current state for internal analysis">
                    <FileSpreadsheet className="w-4 h-4" />
                    <span className="hidden xl:inline">Export State</span>
                </Button>
                <Button variant="ghost" size="sm" onClick={handleExportClient} className="gap-2 text-charcoal-600" title="Export plan for client sharing">
                    <Share2 className="w-4 h-4" />
                    <span className="hidden xl:inline">Client Export</span>
                </Button>
            </div>

            {/* Legend Toggle */}
            <div className="relative">
                <Button variant="ghost" size="sm" onClick={() => setShowLegend(!showLegend)} className="gap-2 text-charcoal-500 hover:text-charcoal-900 hover:bg-charcoal-100">
                    <Info className="w-4 h-4" />
                    <span className="hidden sm:inline">Legend</span>
                </Button>
            </div>
        </div>
      </div>

      {/* Legend Popover */}
      {showLegend && (
        <>
        <div className="fixed inset-0 z-40" onClick={() => setShowLegend(false)} />
        <div className="absolute right-6 top-16 w-72 bg-white/95 backdrop-blur-md rounded-xl shadow-xl border border-charcoal-200 p-4 z-50 transition-all animate-in fade-in zoom-in-95 duration-200">
            <div className="flex items-center justify-between mb-4 pb-2 border-b border-charcoal-100">
                <h4 className="text-xs font-semibold text-charcoal-500 uppercase tracking-wider">Project Key</h4>
                <button onClick={() => setShowLegend(false)} className="text-charcoal-400 hover:text-charcoal-600 rounded-full p-1 hover:bg-charcoal-100 transition-colors"><X className="w-3 h-3" /></button>
            </div>
            <div className="space-y-3 max-h-[60vh] overflow-y-auto pr-1 custom-scrollbar">
                {MOCK_PROJECTS.map(p => (
                    <div key={p.id} className="flex items-start gap-3 group">
                        <div className={`mt-1 w-3 h-3 rounded-full flex-shrink-0 ${PASTEL_VARIANTS[p.color].bg} border ${PASTEL_VARIANTS[p.color].border} shadow-sm`}></div>
                        <div className="flex flex-col">
                             <span className="text-sm font-medium text-charcoal-800 leading-tight group-hover:text-blue-600 transition-colors">{p.name}</span>
                             <span className="text-[11px] text-charcoal-500 mt-0.5">{p.client}</span>
                        </div>
                        {p.status === 'opportunity' && (
                           <span className="ml-auto text-[9px] uppercase font-bold text-orange-600 bg-orange-50 px-1.5 py-0.5 rounded border border-orange-100 tracking-wide">Opp</span>
                        )}
                    </div>
                ))}
            </div>
        </div>
        </>
      )}

      {/* Main Content Area - Scrollable */}
      <div className="flex-1 overflow-auto bg-gray-50/50 p-4 sm:p-6 custom-scrollbar">
        <div className="flex flex-col gap-8 pb-10">
          {quarterMonths.map((month) => {
            const isCurrentMonth = isSameMonth(month.date, new Date());

            // Calculate weeks for this month
            const weeks: { weekNum: number; days: Date[] }[] = [];
            let currentWeekNum = -1;
            let currentWeekDays: Date[] = [];

            month.days.forEach((date) => {
                const w = getISOWeek(date);
                if (w !== currentWeekNum) {
                    if (currentWeekDays.length > 0) {
                        weeks.push({ weekNum: currentWeekNum, days: currentWeekDays });
                    }
                    currentWeekNum = w;
                    currentWeekDays = [date];
                } else {
                    currentWeekDays.push(date);
                }
            });
            if (currentWeekDays.length > 0) {
                weeks.push({ weekNum: currentWeekNum, days: currentWeekDays });
            }

            return (
              <div key={month.name} className={`bg-white border rounded-xl shadow-sm overflow-hidden flex flex-col ${isCurrentMonth ? 'border-blue-200 ring-1 ring-blue-100' : 'border-charcoal-200'}`}>
                {/* Month Block Header */}
                <div className="px-5 py-3 bg-charcoal-50 border-b border-charcoal-200 flex justify-between items-center">
                    <div className="flex items-center gap-3">
                         <h3 className={`font-bold text-lg ${isCurrentMonth ? 'text-blue-800' : 'text-charcoal-700'}`}>{month.fullName}</h3>
                         {isCurrentMonth && <span className="text-[10px] font-bold text-blue-600 bg-white border border-blue-200 px-2 py-0.5 rounded-full uppercase tracking-wide">Current Month</span>}
                    </div>
                </div>

                {/* The Grid */}
                <div className="overflow-x-auto custom-scrollbar">
                  <div className="min-w-[1000px]"> {/* Minimum width to prevent crushing, allows scroll on mobile */}

                    {/* Grid Header */}
                    <div className="flex border-b border-charcoal-200">
                      <div className="w-64 flex-shrink-0 sticky left-0 bg-white z-20 p-3 font-medium text-charcoal-500 border-r border-charcoal-200 flex items-end pb-2">
                        Employee
                      </div>
                      <div className="flex flex-1">
                        {weeks.map((week, wIdx) => (
                          <div key={`${month.name}-w-${wIdx}`} className="flex flex-col border-r border-charcoal-200 last:border-r-0" style={{ flexGrow: week.days.length }}>
                            <div className="h-6 flex items-center justify-center text-[10px] font-bold text-charcoal-400 bg-white/50 border-b border-charcoal-100 uppercase tracking-wider">
                              KW{week.weekNum}
                            </div>
                            <div className="flex h-10 w-full">
                              {week.days.map(date => {
                                const isWknd = isWeekend(date);
                                const isTdy = isToday(date);
                                return (
                                  <div 
                                    key={date.toISOString()} 
                                    className={`flex-1 min-w-[32px] flex flex-col items-center justify-center border-r border-charcoal-100 text-xs 
                                      ${isWknd ? 'bg-charcoal-50 text-charcoal-400' : 'text-charcoal-700'}
                                      ${isTdy ? 'bg-blue-50 text-blue-600 font-bold' : ''}
                                      last:border-r-0
                                    `}
                                  >
                                    <span>{format(date, 'EEE')}</span>
                                    <span className="font-medium">{format(date, 'd')}</span>
                                  </div>
                                );
                              })}
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>

                    {/* Grid Body */}
                    <div>
                      {employees.map(emp => {
                         const util = getUtilization(emp.id, month.days);
                         const isFullyBooked = util.percentage >= 100;
                         const isDraggingRow = draggingEmpId === emp.id;

                         return (
                          <div key={emp.id} className="flex group border-b border-charcoal-100 last:border-0 hover:bg-charcoal-50/30 transition-colors">
                            {/* Employee Card */}
                            <div className="w-64 flex-shrink-0 sticky left-0 bg-white group-hover:bg-charcoal-50/50 z-10 border-r border-charcoal-200 p-3 flex items-center justify-between transition-colors">
                              <div className="flex items-center gap-3">
                                <img src={emp.avatar} alt={emp.name} className="w-8 h-8 rounded-full border border-charcoal-200" />
                                <div>
                                  <div className="flex items-center gap-2">
                                    <div className="text-sm font-medium text-charcoal-900">{emp.name}</div>
                                    <button 
                                      onClick={(e) => {
                                          e.stopPropagation();
                                          setSelectedCell({ empId: emp.id, date: month.days[0] });
                                      }}
                                      className="text-charcoal-400 hover:text-blue-600 hover:bg-blue-50 p-0.5 rounded transition-all opacity-0 group-hover:opacity-100 focus:opacity-100"
                                      title={`Assign Project in ${month.name}`}
                                    >
                                      <Plus className="w-3.5 h-3.5" />
                                    </button>
                                  </div>
                                  <div className="text-xs text-charcoal-500">{emp.role}</div>
                                </div>
                              </div>
                              <div className="text-right">
                                <div className={`text-xs font-bold ${isFullyBooked ? 'text-green-600' : 'text-charcoal-500'}`}>
                                  {util.percentage}%
                                </div>
                                <div className="text-[10px] text-charcoal-400">
                                  {util.assignedDays}/{util.workingDays} d
                                </div>
                              </div>
                            </div>

                            {/* Cells */}
                            <div className="flex flex-1">
                              {month.days.map(date => {
                                const cellAssignments = getAssignmentsForCell(emp.id, date);
                                const isWknd = isWeekend(date);

                                return (
                                  <div 
                                    key={date.toISOString()}
                                    onClick={() => !isWknd && handleCellClick(emp.id, date)}
                                    onDragOver={(e) => !isWknd && handleDragOver(e, emp.id)}
                                    onDrop={(e) => !isWknd && handleDrop(e, emp.id, date)}
                                    className={`flex-1 min-w-[32px] border-r border-charcoal-100 relative min-h-[50px] flex flex-col p-0.5 gap-0.5 group/cell
                                        ${isWknd ? 'bg-charcoal-50/50 cursor-not-allowed' : 'cursor-pointer'}
                                        ${isDraggingRow && !isWknd ? 'bg-blue-50/30' : 'hover:bg-blue-50/50'}
                                    `}
                                  >
                                    {cellAssignments.map(({ assignment, project }) => (
                                        project ? (
                                            <div 
                                                key={assignment.id} 
                                                draggable
                                                onDragStart={(e) => handleDragStart(e, assignment)}
                                                onDragEnd={handleDragEnd}
                                                title={project.name}
                                                className={`w-full flex-1 rounded-sm ${PASTEL_VARIANTS[project.color].bg} border ${PASTEL_VARIANTS[project.color].border} group/chip relative text-[0px] overflow-hidden cursor-grab active:cursor-grabbing hover:brightness-95 hover:z-10
                                                  ${draggingAssignmentId === assignment.id ? 'opacity-40' : 'opacity-100'}
                                                `}
                                            >
                                                <span className="sr-only">{project.name}</span>
                                                {/* Grip handle for visual cue */}
                                                <div className="absolute left-0.5 top-1/2 -translate-y-1/2 opacity-0 group-hover/chip:opacity-30">
                                                    <GripVertical className="w-2 h-2 text-current" />
                                                </div>
                                                <button 
                                                    onClick={(e) => removeAssignment(assignment.id, e)}
                                                    className="absolute inset-0 hidden group-hover/chip:flex items-center justify-center bg-black/5 text-charcoal-700 backdrop-blur-[1px]"
                                                >
                                                    <X className="w-3 h-3" />
                                                </button>
                                            </div>
                                        ) : null
                                    ))}

                                    {/* Quick Add Button on Hover */}
                                    {!isWknd && (
                                        <div className="absolute inset-x-0 bottom-0 flex justify-center pb-0.5 opacity-0 group-hover/cell:opacity-100 transition-opacity pointer-events-none z-20">
                                            <button 
                                                className="bg-blue-600 text-white rounded-full w-4 h-4 flex items-center justify-center shadow-sm hover:scale-110 hover:bg-blue-700 transition-all pointer-events-auto"
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    handleCellClick(emp.id, date);
                                                }}
                                                title="Add Project"
                                            >
                                                <Plus className="w-3 h-3" />
                                            </button>
                                        </div>
                                    )}
                                  </div>
                                );
                              })}
                            </div>
                          </div>
                         );
                      })}
                    </div>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {/* Project Selector Modal - Updated for Multi-select */}
      {selectedCell && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/20 backdrop-blur-sm" onClick={() => setSelectedCell(null)}>
          <div className="bg-white rounded-xl shadow-xl border border-charcoal-200 p-6 w-96 animate-in fade-in zoom-in-95 duration-200 flex flex-col max-h-[85vh]" onClick={e => e.stopPropagation()}>
