    const num = parseFloat(budgetStr.replace(/[^0-9.]/g, ''));
    if (isNaN(num)) return 0;
    if (budgetStr.toLowerCase().includes('k')) return num * 1000;
    if (budgetStr.toLowerCase().includes('m')) return num * 1000000;
    return num;
