import { createContext, useContext, useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { format } from 'date-fns';
import { enUS, de, fr, es, ptBR, it, zhCN, ja } from 'date-fns/locale';
import { Locale } from 'date-fns';
import { enGB } from 'date-fns/locale';

import { TimeZone } from '@models/Timezone';
import { useSettingsContext } from './SettingsContext';
import { useCurrentVersionContext } from './CurrentVersionContext';
import { constants } from '@lib/constants';

interface LanguageContextType {
    formatDate: (date: Date | string | number | null) => string;
    formatDateWithTime: (date: Date | string | number | null) => string;
    formatTime: (date: Date | string | number | null) => string;
    formatVersionDate: (versionDate: Date | string | number | null) => string;
    locale: Locale;
}

const LanguageContext = createContext<LanguageContextType>({
    formatDate: (date) => (date ? format(new Date(date), 'yyyy-MM-dd') : ''),
    formatDateWithTime: (date) => (date ? format(new Date(date), 'yyyy-MM-dd HH:mm') : ''),
    formatTime: (date) => (date ? format(new Date(date), 'HH:mm') : ''),
    formatVersionDate: (versionDate) => (versionDate ? format(new Date(versionDate), 'dd.MM.yyyy HH:mm') : ''),
    locale: enUS,
});

export const useLanguageContext = () => useContext(LanguageContext);

export const LanguageProvider = ({ children }: { children: React.ReactNode }) => {
    const { i18n } = useTranslation();
    const { settings } = useSettingsContext();
    const { currentVersion } = useCurrentVersionContext();

    const locale = useMemo(() => {
        switch (i18n.language) {
            case 'de':
                return de;
            case 'fr':
                return fr;
            case 'es':
                return es;
            case 'pt-BR':
                return ptBR;
            case 'it':
                return it;
            case 'zh-CN':
                return zhCN;
            case 'ja':
                return ja;
            case 'en-GB':
                return enGB;
            default:
                return enUS;
        }
    }, [i18n.language]);

    const formatDate = (date: Date | string | number | null) =>
        date ? format(new Date(date), 'yyyy-MM-dd', { locale }) : '';

    const formatTime = (date: Date | string | number | null) =>
        date ? format(new Date(date), 'HH:mm', { locale }) : '';

    const formatDateWithTime = (date: Date | string | number | null) =>
        date ? format(new Date(date), 'yyyy-MM-dd HH:mm', { locale }) : '';

    const formatVersionDate = (versionDate: Date | string | number | null) => {
        if (!versionDate) return '';

        const parsedDate = new Date(versionDate);
        const hours = parsedDate.getHours();
        const minutes = parsedDate.getMinutes();

        return format(new Date(versionDate), `dd.MM.yyyy ${hours}:${minutes}`, { locale });
    };


    const contextValue = useMemo<LanguageContextType>(
        () => ({
            formatDate,
            formatDateWithTime,
            formatTime,
            formatVersionDate,
            locale,
        }),
        [formatDate, formatDateWithTime, formatTime, formatVersionDate, locale],
    );

    return <LanguageContext.Provider value={contextValue}>{children}</LanguageContext.Provider>;
};
