                    {/* Spinner */}
                    <div className="relative my-4">
                        <div className="absolute inset-0 bg-blue-500 blur-xl opacity-20 rounded-full animate-pulse"></div>
                        <div className="relative bg-charcoal-900 text-blue-400 font-mono text-2xl w-12 h-12 flex items-center justify-center rounded-xl border border-charcoal-700 shadow-xl">
                            <AsciiSpinner />
                        </div>
                    </div>

                    {/* Mock terminal output for sci-fi feel */}
                    <div className="mt-4 w-full max-w-md bg-charcoal-900 rounded-lg p-3 text-left font-mono text-xs text-green-400 border border-charcoal-800 shadow-inner opacity-80">
                        <div className="flex gap-2 mb-1">
                            <span className="text-blue-400">➜</span>
                            <span className="text-white">analyze --target=q1_forecast --deep</span>
                        </div>
                        <div className="text-charcoal-500 mb-1">Loading context... Done</div>
                        <div className="text-charcoal-500 mb-1">Parsing quarterly metrics... Done</div>
                        <div className="flex gap-1">
                            <span className="text-charcoal-500">Reasoning</span>
                            <AsciiSpinner className="text-green-400" />
                        </div>
                    </div>
                </div>
            ) : analysisResult ? (
                <div className="prose prose-sm max-w-none prose-headings:text-charcoal-900 prose-p:text-charcoal-700">
                    <div className="whitespace-pre-wrap">{analysisResult}</div>
                </div>
            ) : null}
         </div>
      </Modal>
    </div>
  );
};

