const ParsedResultDisplay: React.FC<{ rawText: string }> = ({ rawText }) => {
    // Parser Logic
    const parsedData = useMemo(() => {
        const sections: { type: 'header' | 'status' | 'risk' | 'action' | 'text', title?: string, content: string, items?: string[] }[] = [];

        // Normalize text
        const text = rawText.replace(/\*\*/g, ''); // Remove bold markers for cleaner parsing
        const lines = text.split('\n').filter(line => line.trim() !== '');

        let currentSection: any = null;

        lines.forEach(line => {
            // Heuristic Detection
            const lower = line.toLowerCase();

            if (line.includes('Strategische Zusammenfassung') || line.includes('Strategic Summary')) {
                if (currentSection) sections.push(currentSection);
                currentSection = { type: 'header', content: line };
            } else if (lower.includes('status:') || lower.includes('kapazitätsstatus')) {
                if (currentSection) sections.push(currentSection);
                // Extract percentage if present
                const percentMatch = line.match(/(\d+)%/);
                const percentage = percentMatch ? percentMatch[1] : null;
                currentSection = { type: 'status', title: 'SYSTEM STATUS', content: line, percentage };
            } else if (lower.includes('risiko') || lower.includes('risk') || lower.includes('lücken') || lower.includes('gaps')) {
                if (currentSection) sections.push(currentSection);
                currentSection = { type: 'risk', title: 'THREAT ASSESSMENT', content: '' };
            } else if (lower.includes('empfehlungen') || lower.includes('recommendations')) {
                if (currentSection) sections.push(currentSection);
                currentSection = { type: 'action', title: 'TACTICAL RECOMMENDATIONS', content: '', items: [] };
            } else if (line.match(/^\d+\./)) {
                // Numbered list item
                if (currentSection && currentSection.type === 'action') {
                    currentSection.items.push(line.replace(/^\d+\.\s*/, ''));
                } else {
                     if (currentSection) currentSection.content += ' ' + line;
                }
            } else {
                if (currentSection) {
                    currentSection.content += (currentSection.content ? '\n' : '') + line;
                } else {
                    currentSection = { type: 'text', content: line };
                }
            }
        });
        if (currentSection) sections.push(currentSection);

        return sections;
    }, [rawText]);

    return (
        <div className="flex flex-col gap-4 font-mono text-sm relative">
            {/* CRT Overlay Effect */}
            <div className="absolute inset-0 pointer-events-none z-0 opacity-10 bg-[linear-gradient(rgba(18,16,16,0)_50%,rgba(0,0,0,0.25)_50%),linear-gradient(90deg,rgba(255,0,0,0.06),rgba(0,255,0,0.02),rgba(0,0,255,0.06))] bg-[length:100%_2px,3px_100%]"></div>

            {parsedData.map((section, idx) => {
                const delay = { animationDelay: `${idx * 150}ms` };

                if (section.type === 'header') {
                    return (
                        <div key={idx} className="bg-charcoal-800/50 border-b border-charcoal-600 pb-2 mb-2 animate-fade-in-up" style={delay}>
                            <h3 className="text-blue-400 font-bold tracking-widest uppercase flex items-center gap-2">
                                <Activity className="w-4 h-4 animate-pulse" />
                                {section.content}
                            </h3>
                        </div>
                    );
                }

                if (section.type === 'status') {
                    return (
                        <div key={idx} className="bg-charcoal-800/80 border border-blue-500/30 rounded-lg p-4 relative overflow-hidden group animate-slide-in-right" style={delay}>
                            <div className="absolute top-0 right-0 p-2 opacity-20 group-hover:opacity-40 transition-opacity">
                                <Cpu className="w-16 h-16" />
                            </div>
                            <div className="flex items-center gap-4 relative z-10">
                                {section.percentage && (
                                    <div className="w-16 h-16 rounded-full border-4 border-blue-500/50 flex items-center justify-center bg-charcoal-900 shadow-[0_0_15px_rgba(59,130,246,0.3)]">
                                        <span className="text-xl font-bold text-blue-400">{section.percentage}%</span>
                                    </div>
                                )}
                                <div>
                                    <div className="text-xs text-blue-500/80 uppercase tracking-widest mb-1">{section.title}</div>
                                    <div className="text-gray-200 leading-relaxed">{section.content}</div>
                                </div>
                            </div>
                        </div>
                    );
                }

                if (section.type === 'risk') {
                    return (
                        <div key={idx} className="bg-red-900/10 border-l-4 border-red-500/60 p-4 rounded-r-lg relative animate-fade-in-up" style={delay}>
                            {/* Dotted Line Decoration */}
                            <div className="absolute top-0 right-0 w-24 h-px border-t border-dashed border-red-500/30"></div>

                            <div className="flex items-start gap-3">
                                <ShieldAlert className="w-5 h-5 text-red-400 mt-0.5 animate-pulse-subtle" />
                                <div>
                                    <div className="text-xs text-red-400 uppercase tracking-widest mb-1 font-bold">{section.title}</div>
                                    <div className="text-red-100/90 text-xs leading-relaxed">
                                        {section.content}
                                    </div>
                                </div>
                            </div>
                        </div>
                    );
                }

                if (section.type === 'action') {
                    return (
                        <div key={idx} className="mt-2 animate-fade-in-up" style={delay}>
                            <div className="flex items-center gap-2 mb-3 border-b border-charcoal-700 pb-1">
                                <Zap className="w-4 h-4 text-yellow-400" />
                                <span className="text-xs text-yellow-400 uppercase tracking-widest font-bold">{section.title}</span>
                            </div>
                            <div className="space-y-2">
                                {section.items?.map((item, i) => (
                                    <div key={i} className="flex gap-3 bg-charcoal-800/40 p-2 rounded border border-charcoal-700/50 hover:border-yellow-500/30 transition-colors">
                                        <div className="text-yellow-500/50 font-bold">0{i + 1}</div>
                                        <div className="text-gray-300 text-xs">{item}</div>
                                        <CheckSquare className="w-4 h-4 text-green-500/20 ml-auto flex-shrink-0" />
                                    </div>
                                ))}
                            </div>
                        </div>
                    );
                }

                return (
                    <div key={idx} className="text-gray-400 text-xs animate-fade-in" style={delay}>
                        {section.content}
                    </div>
                );
            })}
        </div>
    );
};

export const QuarterlyForecast: React.FC<QuarterlyForecastProps> = ({ data, allProjects, onUpdateForecast, readOnly = false }) => {
  const { t, formatDate, language } = useLanguage();
  const { apiKey, isAiEnabled } = useSettings();
  const [addingTo, setAddingTo] = useState<{ qId: string, type: 'mustWin' | 'alternative' } | null>(null);

  // AI State
  const [analyzing, setAnalyzing] = useState(false);
  const [analysisResult, setAnalysisResult] = useState<string | null>(null);
  const [isAnalysisModalOpen, setIsAnalysisModalOpen] = useState(false);

  const calculateCapacity = (q: QuarterData) => {
    const totalCap = q.totalCapacity.reduce((a, b) => a + b, 0);
    const assignedDays = q.runningProjects.reduce((acc, p) => acc + (p.volume || 60), 0);

    const rawAvailable = totalCap - assignedDays;
    // Ensure Available is non-negative for display
    const availableAfterRunning = Math.max(0, rawAvailable);

    const opportunityDays = q.mustWinOpportunities.reduce((acc, p) => acc + (p.volume || 0), 0);
    // Final/Net capacity uses raw values to reflect true over/under capacity
    const finalAvailable = rawAvailable - opportunityDays;

    return { totalCap, assignedDays, availableAfterRunning, opportunityDays, finalAvailable };
  };

  const getMonthlyBreakdown = (q: QuarterData, metrics: any) => {
      if (metrics.totalCap === 0) return q.months.map((m, i) => ({ month: m, total: q.totalCapacity[i], available: 0, optimistic: 0 }));

      return q.months.map((month, index) => {
          const total = q.totalCapacity[index];
          const ratio = total / metrics.totalCap;
          const assigned = Math.round(metrics.assignedDays * ratio);
          const opportunities = Math.round(metrics.opportunityDays * ratio);

          const rawAvailable = total - assigned;
          const available = Math.max(0, rawAvailable); // Display as 0 if negative
          const optimistic = rawAvailable - opportunities; // Keep true net value

          return { month, total, available, optimistic };
      });
  };

  const handleExportPPT = () => {
    alert(t('forecast.generatingPPT'));
  };

  const handleAIAnalysis = async () => {
    if (!isAiEnabled) return;
    setAnalyzing(true);
    setAnalysisResult(null);
    setIsAnalysisModalOpen(true);

    try {
        // Analyze only the current/first quarter for now, passing the selected language
        const result = await generateForecastAnalysis(data[0], apiKey, language);
        setAnalysisResult(result);
    } catch (error) {
        setAnalysisResult(t('forecast.analysisError'));
    } finally {
        setAnalyzing(false);
    }
  };

  const handleRequestSAP = (project: Project, e: React.MouseEvent) => {
    e.stopPropagation();
    alert(`${t('forecast.requestingSAP')} "${project.name}"`);
  };

  const handleUpdateProject = (
    quarterId: string,
    type: 'mustWin' | 'alternative',
    projects: Project[],
    updatedProject: Project,
    field: 'volume' | 'budget',
    value: string | number
  ) => {
    if (readOnly || !onUpdateForecast) return;

    const updatedList = projects.map(p => {
        if (p.id === updatedProject.id) {
            return { ...p, [field]: value };
        }
        return p;
    });
    onUpdateForecast(quarterId, type, updatedList);
  };

  const handleRemoveProject = (
    quarterId: string,
    type: 'mustWin' | 'alternative',
    projects: Project[],
    projectId: string
  ) => {
    if (readOnly || !onUpdateForecast) return;
    const updatedList = projects.filter(p => p.id !== projectId);
    onUpdateForecast(quarterId, type, updatedList);
  };

  const handleAddProject = (
    quarterId: string,
    type: 'mustWin' | 'alternative',
    currentProjects: Project[],
    newProject: Project
  ) => {
      if (readOnly || !onUpdateForecast) return;
      const projectToAdd = { ...newProject, volume: newProject.volume || 30 };
      onUpdateForecast(quarterId, type, [...currentProjects, projectToAdd]);
      setAddingTo(null);
  };

  return (
    <div className="h-full overflow-auto bg-gray-50/50 p-6">
      <div className="max-w-7xl mx-auto">
        <div className="mb-8 flex justify-between items-end">
            <div>
                <div className="flex items-center gap-3">
                    <h1 className="text-2xl font-semibold text-charcoal-900 tracking-tight">{t('forecast.title')}</h1>
                    {readOnly && (
                        <div className="px-2 py-0.5 rounded text-xs font-bold bg-charcoal-100 text-charcoal-500 flex items-center gap-1 border border-charcoal-200">
                            <Lock className="w-3 h-3" /> Read Only
                        </div>
                    )}
                </div>
                <p className="text-charcoal-500 mt-1">{t('forecast.subtitle')}</p>
            </div>
            <div className="flex gap-3">
                {isAiEnabled && (
                    <Button onClick={handleAIAnalysis} variant="secondary" className="gap-2 shadow-sm border border-charcoal-200 text-blue-700 bg-white hover:bg-blue-50 transition-all hover:scale-105">
                        <Sparkles className="w-4 h-4" />
                        {t('forecast.aiAnalysis')}
                    </Button>
                )}
                <Button onClick={handleExportPPT} className="gap-2 shadow-sm">
                    <Presentation className="w-4 h-4" />
                    {t('forecast.exportPPT')}
                </Button>
            </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {data.map((quarter, index) => {
            const metrics = calculateCapacity(quarter);
            const isCurrent = index === 0;
            const monthlyData = getMonthlyBreakdown(quarter, metrics);
            const isAddingMustWin = addingTo?.qId === quarter.id && addingTo?.type === 'mustWin';
            const isAddingAlt = addingTo?.qId === quarter.id && addingTo?.type === 'alternative';

            const currentIds = [
                ...quarter.runningProjects, 
