                    </div>
                  </div>

                  {/* Must Win Opportunities */}
                  <div>
                     <h3 className="text-xs font-semibold text-charcoal-400 uppercase tracking-wider mb-3 flex items-center gap-2">
                        <TrendingUp className="w-3 h-3" /> {t('forecast.mustWin')}
